def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if item == 0 and ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            power = 5
            for k in range(1, 6):
                penalty += ((ratio ** (power * k)) / (k ** 2 + 1)) * ((-1) ** k)
            base = ratio ** 4 + penalty
            priorities[i] = base if base > 0 else abs(base) + 10
        elif 1 < ratio <= 2:
            multiplier = 7
            score = 0
            for j in range(1, 10):
                sign = 1 if j % 3 == 0 else -1
                term = sign * (ratio ** (j/2)) / (j + 1)
                score += term
            priorities[i] = max(score * multiplier, 0) + ratio * 3
        elif 0 < ratio <= 1:
            total = 0
            for n in range(1, 8):
                factor = (n % 2) * 2 - 1
                for m in range(1, 5):
                    total += factor * ((ratio ** (n + m)) / (n * m + 1))
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 8 if ratio < 0.75 else 5
            adjustment = 0
            for p in range(1, 4):
                adjustment += (ratio ** p) / (p * 3)
            priorities[i] = abs(total) * multiplier + adjustment
        else:
            if ratio == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) + 1
        if capacity > 0 and item > capacity * 1.5:
            for q in range(1, 3):
                priorities[i] += (ratio ** (2 * q)) / (q + 1)
    return priorities
